import { getServerSession } from "next-auth";
import { authOptions } from "../lib/auth";
import { redirect } from "next/navigation";

export default async function DashboardPage() {
  const session = await getServerSession(authOptions);
  if (!session) redirect("/login");

  return (
    <section className="container" style={{ marginTop: '40px' }}>
      {/* ส่วนหัวของ Dashboard (Header) */}
      <header style={{ borderBottom: '2px solid #e2e8f0', paddingBottom: '20px', marginBottom: '30px' }}>
        <h1 style={{ marginBottom: '8px', fontSize: '24px', color: '#0f172a' }}>
          แผงควบคุมและวิเคราะห์ข้อมูลสุขภาพ
        </h1>
        <p className="muted" style={{ margin: 0, fontSize: '15px' }}>
          รายงานสรุปพฤติกรรมทางกายภาพและสภาวะความเครียด (Health Analytics Dashboard) <br/>
          ผู้ใช้งานระบบ: <span style={{ fontWeight: '600', color: '#334155' }}>{session.user?.name}</span>
        </p>
      </header>

      {/* ส่วนแสดงข้อมูลสถิติ (Key Metrics) */}
      <div className="grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px' }}>
        
        {/* การ์ดที่ 1: วิเคราะห์อาการบาดเจ็บ */}
        <article className="card" style={{ borderTop: '4px solid #ef4444', padding: '24px' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            กลุ่มอาการที่พบความถี่สูงสุด
          </h3>
          <p style={{ fontSize: '26px', fontWeight: 'bold', margin: '15px 0', color: '#0f172a' }}>
            อาการปวดบริเวณหลัง
          </p>
          <div style={{ background: '#fee2e2', color: '#b91c1c', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            ข้อควรระวัง: ตรวจพบความเสี่ยงสะสม 4 วันทำการ
          </div>
        </article>

        {/* การ์ดที่ 2: วิเคราะห์ความเครียด/ความเหนื่อยล้า */}
        <article className="card" style={{ borderTop: '4px solid #f59e0b', padding: '24px' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            ดัชนีชี้วัดความเหนื่อยล้าเฉลี่ย
          </h3>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', margin: '15px 0' }}>
            <span style={{ fontSize: '28px', fontWeight: 'bold', color: '#0f172a' }}>3.5</span>
            <span style={{ fontSize: '16px', color: '#64748b' }}>/ 5.0</span>
          </div>
          <div style={{ background: '#fef3c7', color: '#b45309', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            สถานะ: อยู่ในเกณฑ์ที่ต้องเฝ้าระวังระดับกลาง
          </div>
        </article>

        {/* การ์ดที่ 3: วิเคราะห์พฤติกรรมเชิงบวก */}
        <article className="card" style={{ borderTop: '4px solid #10b981', padding: '24px' }}>
          <h3 style={{ color: '#64748b', fontSize: '13px', textTransform: 'uppercase', letterSpacing: '0.5px', marginTop: 0 }}>
            อัตราการปฏิบัติตามหลักการยศาสตร์
          </h3>
          <div style={{ display: 'flex', alignItems: 'baseline', gap: '8px', margin: '15px 0' }}>
            <span style={{ fontSize: '28px', fontWeight: 'bold', color: '#0f172a' }}>2</span>
            <span style={{ fontSize: '16px', color: '#64748b' }}>/ 7 วันทำการ</span>
          </div>
          <div style={{ background: '#d1fae5', color: '#047857', padding: '10px 12px', borderRadius: '6px', fontSize: '13px', fontWeight: '500' }}>
            ข้อเสนอแนะ: ควรเพิ่มความถี่ในการยืดกล้ามเนื้อ
          </div>
        </article>

      </div>
    </section>
  );
}